import { describe, it, expect } from 'vitest';

describe('happy-dom capture phase probe', () => {
  it('capture listener on window fires for scroll dispatched on a descendant', () => {
    let captureFired = false;
    let bubbleFired = false;
    const onCapture = (): void => {
      captureFired = true;
    };
    const onBubble = (): void => {
      bubbleFired = true;
    };
    window.addEventListener('scroll', onCapture, true);
    window.addEventListener('scroll', onBubble, false);

    const div = document.createElement('div');
    document.body.append(div);
    div.dispatchEvent(new Event('scroll'));

    expect(captureFired).toBe(true);
    // scroll events do not bubble, so the non-capture window listener must NOT fire
    expect(bubbleFired).toBe(false);

    window.removeEventListener('scroll', onCapture, true);
    window.removeEventListener('scroll', onBubble, false);
    div.remove();
  });

  it('window scroll/resize events reach a window listener', () => {
    let scrollCount = 0;
    let resizeCount = 0;
    const onScroll = (): void => {
      scrollCount++;
    };
    const onResize = (): void => {
      resizeCount++;
    };
    window.addEventListener('scroll', onScroll, true);
    window.addEventListener('resize', onResize);

    window.dispatchEvent(new Event('scroll'));
    window.dispatchEvent(new Event('resize'));

    expect(scrollCount).toBe(1);
    expect(resizeCount).toBe(1);

    window.removeEventListener('scroll', onScroll, true);
    window.removeEventListener('resize', onResize);
  });
});

