/* -----------------------------------------------------------------
 * Menu dismissal on scroll and viewport resize.
 *
 * The dropdown is `position: fixed` at viewport coordinates, so once the
 * user scrolls the `.results` overflow container (or the page) or resizes
 * the window, the menu stays pinned at its old viewport position — now
 * detached from (and possibly misaligned with) the row that owns it.
 * Standard dropdowns close on scroll/resize while open.
 *
 * Contract: while a menu is open it listens for `scroll` (capture phase,
 * on `window`, so it also catches scrolls originating inside the
 * `.results` overflow:auto container — scroll events do not bubble, but a
 * capture-phase ancestor listener still fires) and `resize` (on `window`),
 * either of which closes the menu exactly like Escape / an outside click.
 * Both listeners are removed again on close so they don't leak across
 * open/close cycles.
 * -------------------------------------------------------------- */
describe('menu dismissal on scroll and viewport resize', () => {
  it('closes an open menu when the window scrolls', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [file] }));

    const actions = actionsOf(results, 'a.txt');
    const btn = menuBtnOf(actions);
    const menu = menuOf(actions);

    btn.click();
    expect(menu.hidden).toBe(false);

    window.dispatchEvent(new Event('scroll'));

    expect(menu.hidden).toBe(true);
    expect(btn.getAttribute('aria-expanded')).toBe('false');
  });

  it('closes an open menu when the viewport is resized', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [file] }));

    const actions = actionsOf(results, 'a.txt');
    const btn = menuBtnOf(actions);
    const menu = menuOf(actions);

    btn.click();
    expect(menu.hidden).toBe(false);

    window.dispatchEvent(new Event('resize'));

    expect(menu.hidden).toBe(true);
    expect(btn.getAttribute('aria-expanded')).toBe('false');
  });

  it('closes an open menu when scrolling inside the .results overflow container', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [file] }));

    const actions = actionsOf(results, 'a.txt');
    const btn = menuBtnOf(actions);
    const menu = menuOf(actions);

    btn.click();
    expect(menu.hidden).toBe(false);

    // scroll events do not bubble; only a capture-phase listener on window
    // (an ancestor of .results) catches a scroll dispatched on the
    // container itself. This is how the menu detects inner-container
    // scrolls.
    results.dispatchEvent(new Event('scroll'));

    expect(menu.hidden).toBe(true);
    expect(btn.getAttribute('aria-expanded')).toBe('false');
  });

  it('closes a menu opened via right-click when the window scrolls', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [file] }));

    const row = rowByName(results.querySelector('table')!, 'a.txt')!;
